// src/pages/donor/FundsPage.jsx
import PageHeader from "../../components/shared/PageHeader";
import DataTable  from "../../components/shared/DataTable";
import Badge      from "../../components/shared/Badge";
import { funds }  from "../../data/mockData";

const fmt = (n) => n?.toLocaleString() ?? "–";

export default function FundsPage() {
  return (
    <div>
      <PageHeader title="Available Funds" desc="Active funds open for donations" />
      <div className="card">
        <DataTable
          columns={[
            { key:"id",      label:"Fund ID",  mono:true },
            { key:"name",    label:"Fund Name"           },
            { key:"ngo",     label:"NGO",      mono:true },
            { key:"target",  label:"Target",  render:(r) => <span className="text-gold">{fmt(r.target)}</span> },
            { key:"raised",  label:"Raised",  render:(r) => fmt(r.raised) },
            { key:"donors",  label:"Donors"              },
            { key:"status",  label:"Status",  render:(r) => <Badge type={r.status==="open"?"green":"red"}>{r.status}</Badge> },
          ]}
          data={funds.filter((f) => f.status === "open")}
        />
      </div>
    </div>
  );
}
